#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    int value;
    char msg[32];
} SharedData;

int main(void) {
    SharedData *data = (SharedData *)malloc(sizeof(SharedData));
    data->value = 42;
    strncpy(data->msg, "hello shm", 31);
    printf("data->value = %d\n", data->value);
    printf("data->msg = %s\n", data->msg);
    free(data);
    return 0;
}

