 * Memoire partagee simulee : struct config avec port + host
 * malloc simule shmat(), free simule shmdt()+shmctl(IPC_RMID).
 * ========================================================= */
typedef struct { int port; char host[32]; } Config;

void example_shared_config(void) {
    Config *cfg = (Config *)malloc(sizeof(Config));
    cfg->port = 8080;
    strncpy(cfg->host, "localhost", 31);
    printf("cfg->port = %d\n", cfg->port);
    printf("cfg->host = %s\n", cfg->host);
    free(cfg);
}
